/**
 * Variantes disponíveis:
 *
 * ÍCONE     icon-orange | icon-dark | icon-light | icon-gelo
 * HORIZONTAL  horizontal-dark (fundo escuro) | horizontal-light (fundo claro)
 * VERTICAL    vertical-dark (fundo escuro)   | vertical-orange (fundo laranja)
 *
 * PRODUTO   product="torneio" | product="ferinos"
 *   Layout herdado do variant: icon-* → ícone, horizontal-* → horizontal, vertical-* → vertical
 */

export type LogoVariant =
  | 'icon-orange'
  | 'icon-dark'
  | 'icon-light'
  | 'icon-gelo'
  | 'horizontal-dark'
  | 'horizontal-light'
  | 'vertical-dark'
  | 'vertical-orange';

export type LogoProduct = 'torneio' | 'ferinos';

export interface LogoProps {
  variant?: LogoVariant;
  product?: LogoProduct;
  height?: number;
  className?: string;
  'aria-label'?: string;
}

// ── Helpers ─────────────────────────────────────────────────────────────────

function getLayout(variant: LogoVariant): 'horizontal' | 'vertical' | 'icon' {
  if (variant.startsWith('horizontal')) return 'horizontal';
  if (variant.startsWith('vertical')) return 'vertical';
  return 'icon';
}

