// ── Logo ────────────────────────────────────────────────────────────────────

export function Logo({
  variant = 'horizontal-dark',
  product,
  height = 40,
  className,
  'aria-label': ariaLabel = 'SuaArena',
}: LogoProps) {
  const rawId = useId();
  const uid = rawId.replace(/:/g, '');
  const layout = getLayout(variant);

  if (product) {
    const meta = PRODUCT_META[product][layout];
    const width = height * meta.aspect;
    return (
      <svg
        viewBox={meta.viewBox}
        width={width}
        height={height}
        fill="none"
        className={className}
        aria-label={ariaLabel}
        role="img"
      >
        {product === 'torneio' && layout === 'horizontal' && <TorneiosHorizontal uid={uid} />}
        {product === 'torneio' && layout === 'vertical'   && <TorneiosVertical uid={uid} />}
        {product === 'torneio' && layout === 'icon'       && <TorneiosIcon />}
        {product === 'ferinos' && layout === 'horizontal' && <FerinosHorizontal uid={uid} />}
        {product === 'ferinos' && layout === 'vertical'   && <FerinosVertical uid={uid} />}
        {product === 'ferinos' && layout === 'icon'       && <FerinosIcon />}
      </svg>
    );
  }

  const viewBox = VIEWBOXES[variant];
  const asp = ASPECTS[variant];
  const width = height * asp;

  return (
    <svg
      viewBox={viewBox}
      width={width}
      height={height}
      fill="none"
      className={className}
      aria-label={ariaLabel}
      role="img"
    >
      {variant === 'icon-orange'      && <IconOrange />}
      {variant === 'icon-dark'        && <IconDark />}
      {variant === 'icon-light'       && <IconLight />}
      {variant === 'icon-gelo'        && <IconGelo />}
      {variant === 'horizontal-dark'  && <HorizontalDark uid={uid} />}
      {variant === 'horizontal-light' && <HorizontalLight uid={uid} />}
      {variant === 'vertical-dark'    && <VerticalDark uid={uid} />}
      {variant === 'vertical-orange'  && <VerticalOrange uid={uid} />}
    </svg>
  );
}
